class Solution(object):
    def allCellsDistOrder(self, rows, cols, rCenter, cCenter):
        cells = []
        for i in range(rows):
            for j in range(cols):
                dist = abs(i - rCenter) + abs(j - cCenter)
                cells.append((dist, i, j))
        cells.sort()
        return [[i, j] for _, i, j in cells]
